// src/components/FormComponent.tsx
import { JsonForms } from '@jsonforms/react';
import { GoARenderers } from '@abgov/jsonforms-components';
import { adspFormConfig } from '../config/adspForm';

export default function FormComponent({ onSubmit }) {
  const [schema, setSchema] = useState(null);
  const [uiSchema, setUiSchema] = useState(null);
  const [data, setData] = useState({});

  useEffect(() => {
    if (adspFormConfig.mode === 'mock') {
      // Use mock schemas for prototyping
      setSchema({ type: 'object', properties: { name: { type: 'string' } } });
      setUiSchema({ type: 'VerticalLayout', elements: [] });
    } else {
      // Fetch from Form Service
      loadFormDefinition(adspFormConfig.definitionId);
    }
  }, []);

  return (
    <JsonForms
      schema={schema}
      uischema={uiSchema}
      data={data}
      renderers={GoARenderers}
      onChange={({ data }) => setData(data)}
    />
  );
}
